-- COMPUTER_LITERACY_1 2024년 제1회 기출 복원 — 60문항 일괄 적재
-- mock_exam: kind=PAST_EXAM, visibility=PUBLISHED, expert_verified=0
--
-- 재실행 안전성 — 동일 조합(exam_type + PAST_EXAM + 연도/회차) 정리 후 재삽입
DELETE FROM mock_exam
  WHERE exam_type = 'COMPUTER_LITERACY_1'
    AND kind = 'PAST_EXAM'
    AND exam_year = 2024
    AND exam_round = 1;

SET @seq := (SELECT COALESCE(MAX(sequence), 0) + 1 FROM mock_exam WHERE exam_type = 'COMPUTER_LITERACY_1');
SET @cl1_root := (SELECT id FROM subject WHERE name = '컴퓨터활용능력 1급 필기' AND parent_id IS NULL LIMIT 1);
SET @sub_pc := (SELECT id FROM subject WHERE name = '컴퓨터 일반' AND parent_id = @cl1_root LIMIT 1);
SET @sub_xls := (SELECT id FROM subject WHERE name = '스프레드시트 일반' AND parent_id = @cl1_root LIMIT 1);
SET @sub_db := (SELECT id FROM subject WHERE name = '데이터베이스 일반' AND parent_id = @cl1_root LIMIT 1);

INSERT INTO mock_exam
  (name, exam_type, sequence, visibility, expert_verified,
   kind, exam_year, exam_round, exam_date, created_at, updated_at)
VALUES
  ('컴퓨터활용능력 1급 필기 2024년 1회 복원', 'COMPUTER_LITERACY_1', @seq, 'PUBLISHED', 0,
   'PAST_EXAM', 2024, 1, NULL, NOW(6), NOW(6));

SET @mock_exam_id := LAST_INSERT_ID();

INSERT INTO question
  (subject_id, content, question_type, correct_option, explanation,
   topic, difficulty, mock_exam_id, display_order,
   verification_category, content_hash, created_at, updated_at)
VALUES
  (@sub_pc, '웹 서핑이나 인터넷을 이용할 때 자주 방문하게 되는 웹사이트로, 전자우편·뉴스·쇼핑·게시판 등 다양한 서비스를 통합해 제공하는 사이트는?\n\n① 커머셜 사이트\n② 미러 사이트\n③ 포털 사이트\n④ 커뮤니티 사이트', 'MCQ', 3, '정답: 3. 포털 사이트는 검색, 전자우편, 뉴스, 쇼핑, 게시판 등 여러 인터넷 서비스를 통합 제공하는 관문 사이트이다.\n\n**오답 풀이**\n- 1번: 커머셜 사이트는 상업적 목적으로 운영되는 사이트이다.\n- 2번: 미러 사이트는 같은 내용을 복사해 분산 제공하는 사이트이다.\n- 3번: 포털 사이트는 다양한 인터넷 서비스를 통합해 제공한다.\n- 4번: 커뮤니티 사이트는 사용자 사이의 소통과 게시판 중심으로 운영된다.\n\n**보충 개념**\n포털은 사용자가 인터넷 서비스를 이용할 때 출발점 역할을 하는 사이트를 가리킨다.',
   '포털 사이트', 1, @mock_exam_id, 1, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '한글 Windows 10에서 사용하는 바로 가기 키에 대한 설명으로 옳지 않은 것은?\n\n① [Win] + E : 파일 탐색기 열기\n② [Win] + I : 설정 열기\n③ [Win] + P : 프레젠테이션 표시 모드 선택\n④ [Win] + X : 접근성 센터 열기', 'MCQ', 4, '정답: 4. [Win]+X는 시작 단추의 빠른 링크 메뉴를 여는 단축키이며, 접근성 센터는 [Win]+U로 연다.\n\n**오답 풀이**\n- 1번: [Win]+E는 파일 탐색기를 연다.\n- 2번: [Win]+I는 설정을 연다.\n- 3번: [Win]+P는 화면 표시·프레젠테이션 모드를 선택한다.\n- 4번: [Win]+X는 접근성 센터가 아니라 빠른 링크 메뉴를 연다.\n\n**보충 개념**\nWindows 단축키는 시스템 기능을 빠르게 호출하기 위한 조합 키이다.',
   'Windows 단축키', 1, @mock_exam_id, 2, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '모바일 인터넷에 접속해 음악 파일이나 음원을 제공받는 주문형 음악 서비스이며, 스트리밍 기술을 이용해 실시간으로도 들을 수 있는 것은?\n\n① MOD\n② VDT\n③ PDA\n④ VOD', 'MCQ', 1, '정답: 1. MOD는 Music On Demand의 약자로 주문형 음악 서비스를 의미한다.\n\n**오답 풀이**\n- 1번: MOD는 주문형 음악 서비스이다.\n- 2번: VDT는 영상 표시 단말 장치이다.\n- 3번: PDA는 휴대용 개인 정보 단말기이다.\n- 4번: VOD는 주문형 비디오 서비스이다.\n\n**보충 개념**\nMOD는 다운로드 없이 스트리밍 방식으로 음악을 제공받을 수 있는 서비스이다.',
   'MOD', 1, @mock_exam_id, 3, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '인터넷 통신 장비인 게이트웨이(Gateway)의 기본 역할에 대한 설명으로 알맞은 것은?\n\n① 현재 위치한 네트워크에서 다른 네트워크로 연결할 때 사용된다.\n② 인터넷 신호를 증폭하며 먼 거리로 정보를 전달할 때 사용된다.\n③ 네트워크 계층의 연동 장치로 경로 설정에 사용된다.\n④ 문자로 된 도메인 이름을 숫자로 이루어진 실제 IP 주소로 변환하는 데 사용된다.', 'MCQ', 1, '정답: 1. 게이트웨이는 서로 다른 네트워크를 연결해 주는 관문 역할을 한다.\n\n**오답 풀이**\n- 1번: 게이트웨이는 다른 네트워크로 연결할 때 사용된다.\n- 2번: 신호 증폭은 리피터의 역할에 가깝다.\n- 3번: 경로 설정은 라우터의 핵심 기능이다.\n- 4번: 도메인 이름을 IP 주소로 변환하는 것은 DNS의 역할이다.\n\n**보충 개념**\n게이트웨이는 프로토콜이 다른 네트워크 사이의 통신을 중계할 수 있다.',
   '게이트웨이', 1, @mock_exam_id, 4, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, 'CPU와 GPU에 대한 설명으로 옳지 않은 것은?\n\n① CPU는 중앙 처리 장치이고, GPU는 컴퓨터 그래픽을 처리하는 장치이다.\n② GPU는 비메모리 분야 반도체로서 CPU보다 비싸다.\n③ CPU는 병렬 처리 방식이고, GPU는 직렬 처리 방식이다.\n④ GPU는 영상 편집이나 게임 등의 멀티미디어 작업에서부터 인공지능(AI)의 핵심 부품으로 각광받고 있다.', 'MCQ', 3, '정답: 3. CPU는 직렬 처리에 강하고, GPU는 다수의 코어를 활용한 병렬 처리에 강하므로 보기의 처리 방식 설명이 반대로 되어 있다.\n\n**오답 풀이**\n- 1번: CPU와 GPU의 기본 설명으로 적절하다.\n- 2번: GPU는 고성능 비메모리 반도체로 분류된다.\n- 3번: CPU와 GPU의 처리 방식 설명이 뒤바뀌어 있다.\n- 4번: GPU는 그래픽 처리와 AI 연산에 폭넓게 활용된다.\n\n**보충 개념**\nGPU는 동일한 연산을 대량의 데이터에 병렬로 수행하는 작업에 적합하다.',
   'CPU와 GPU', 1, @mock_exam_id, 5, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, 'CPU가 프로그램의 명령어를 수행하는 도중 산술·논리 연산의 결과를 일시적으로 저장하는 레지스터로 알맞은 것은?\n\n① 명령어 레지스터(IR)\n② 주소 레지스터(MAR)\n③ 누산기(AC)\n④ 프로그램 카운터(PC)', 'MCQ', 3, '정답: 3. 누산기(AC)는 산술·논리 연산 결과를 일시적으로 보관하는 레지스터이다.\n\n**오답 풀이**\n- 1번: 명령어 레지스터는 현재 수행 중인 명령어를 저장한다.\n- 2번: 주소 레지스터는 메모리 주소를 저장한다.\n- 3번: 누산기는 산술·논리 연산 결과를 저장한다.\n- 4번: 프로그램 카운터는 다음에 실행할 명령어 주소를 저장한다.\n\n**보충 개념**\nCPU 내부 레지스터는 명령어 실행 과정에서 필요한 값과 주소를 빠르게 보관한다.',
   '레지스터', 1, @mock_exam_id, 6, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '이미지 표현 방식에 대한 설명으로 옳지 않은 것은?\n\n① 비트맵 방식은 그림을 확대 또는 축소할 때 화질의 손상이 거의 없다.\n② 비트맵 방식으로 저장된 이미지는 벡터 방식에 비해 메모리를 적게 차지하며, 보여주는 속도가 느리다.\n③ 벡터 방식은 점과 점을 연결하는 직선이나 곡선을 이용하여 이미지를 표현하는 방식이다.\n④ 벡터 방식은 그림을 픽셀(Pixel)이라고 하는 여러 개의 점으로 표시하는 방식이다.', 'MCQ', 2, '정답: 2. 비트맵 방식은 픽셀 단위로 이미지를 표현하므로 일반적으로 벡터 방식보다 더 많은 메모리를 차지한다.\n\n**오답 풀이**\n- 1번: 보기 ①의 비트맵 확대·축소 설명도 부정확하지만, 정답표 기준 정답은 ②이다.\n- 2번: 비트맵이 벡터보다 메모리를 적게 차지한다는 설명은 잘못되었다.\n- 3번: 벡터 방식은 수학적인 선과 곡선으로 이미지를 표현한다.\n- 4번: 픽셀로 표현하는 것은 비트맵 방식의 특징이다.\n\n**보충 개념**\n비트맵은 확대 시 계단 현상이 나타날 수 있고, 벡터는 확대해도 화질 손상이 적다.',
   '이미지 표현 방식', 2, @mock_exam_id, 7, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '비밀키 암호화 기법의 특징으로 보기 어려운 것은?\n\n① 사용자의 증가에 따라 관리해야 하는 키의 수가 상대적으로 많아진다.\n② 대표적으로 DES(Data Encryption Standard)\n③ 이중 키 방식이므로 알고리즘이 복잡하다.\n④ 암호화와 복호화의 속도가 빠르다.', 'MCQ', 3, '정답: 3. 이중 키 방식은 공개키 암호화 기법의 특징이며 비밀키 암호화 기법의 특징이 아니다.\n\n**오답 풀이**\n- 1번: 비밀키 방식은 사용자가 늘어날수록 관리해야 할 키의 수가 많아진다.\n- 2번: DES는 대표적인 비밀키 암호화 알고리즘이다.\n- 3번: 이중 키 방식은 공개키 암호화 방식의 특징이다.\n- 4번: 비밀키 방식은 일반적으로 암호화와 복호화 속도가 빠르다.\n\n**보충 개념**\n비밀키 암호는 암호화와 복호화에 같은 키를 사용한다.',
   '비밀키 암호', 1, @mock_exam_id, 8, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '멀티미디어에 대한 설명으로 옳지 않은 것은?\n\n① 멀티미디어와 관련된 표준안은 그래픽, 오디오, 문서 등 매우 다양하다.\n② 대표적인 정지화상 표준으로는 손실 및 무손실 압축 기법을 모두 사용할 수 있는 JPEG과 무손실 압축 기법을 사용하는 GIF가 있다.\n③ MPEG은 Intel사가 개발한 동영상 압축 기술로, 용량이 작고 음질이 뛰어나다.\n④ 스트리밍이 지원되는 파일 형식은 ASF, WMV, RAM 등이 있다.', 'MCQ', 3, '정답: 3. MPEG은 동화상 전문가 그룹이 제정한 동영상 압축 국제 표준이며, Intel사가 개발한 것은 DVI 기술이다.\n\n**오답 풀이**\n- 1번: 멀티미디어 표준은 그래픽, 오디오, 문서 등 다양한 분야에 걸쳐 있다.\n- 2번: JPEG과 GIF는 대표적인 정지화상 관련 형식이다.\n- 3번: MPEG을 Intel사가 개발했다고 한 부분이 옳지 않다.\n- 4번: ASF, WMV, RAM은 스트리밍과 관련된 파일 형식이다.\n\n**보충 개념**\nMPEG은 동영상과 오디오 데이터 압축 표준으로 널리 활용된다.',
   '멀티미디어', 2, @mock_exam_id, 9, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '컴퓨터의 기본 기능 중 제어 기능에 해당하는 설명은?\n\n① 자료와 명령을 컴퓨터에 입력하는 기능\n② 산술적/논리적 연산을 수행하는 기능\n③ 입력된 자료들을 주기억 장치나 보조기억 장치에 기억하거나 저장하는 기능\n④ 입출력 및 저장, 연산 장치들에 대한 지시 또는 감독 기능을 수행하는 기능', 'MCQ', 4, '정답: 4. 제어 기능은 컴퓨터를 구성하는 각 장치의 동작을 지시하고 감독하는 기능이다.\n\n**오답 풀이**\n- 1번: 입력 기능에 대한 설명이다.\n- 2번: 연산 기능에 대한 설명이다.\n- 3번: 기억 기능에 대한 설명이다.\n- 4번: 제어 기능에 대한 설명이다.\n\n**보충 개념**\n컴퓨터의 기본 기능은 입력, 기억, 연산, 제어, 출력으로 구분된다.',
   '컴퓨터 기본 기능', 1, @mock_exam_id, 10, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '한글 Windows 10에서의 인쇄 작업에 대한 설명으로 옳지 않은 것은?\n\n① 프린터 추가에 의해 가장 먼저 설치된 프린터가 공유된다.\n② 이미 설치한 프린터를 다른 이름으로 다시 설치할 수 있다.\n③ 네트워크 프린터를 사용할 때는 프린터의 공유 이름과 프린터가 연결되어 있는 컴퓨터의 이름을 알아야 한다.\n④ 기본 프린터란 인쇄 명령 수행 시 특정 프린터를 지정하지 않을 경우 자동으로 인쇄 작업이 전달되는 프린터로, 하나만 지정할 수 있다.', 'MCQ', 1, '정답: 1. 프린터 공유는 자동으로 설정되는 것이 아니라 사용자가 직접 공유 설정을 해 주어야 한다.\n\n**오답 풀이**\n- 1번: 가장 먼저 설치된 프린터가 자동으로 공유된다는 설명은 옳지 않다.\n- 2번: 같은 프린터도 다른 이름으로 다시 설치할 수 있다.\n- 3번: 네트워크 프린터 사용 시 공유 이름과 연결된 컴퓨터 이름이 필요할 수 있다.\n- 4번: 기본 프린터는 하나만 지정할 수 있다.\n\n**보충 개념**\n프린터 공유는 네트워크상의 다른 사용자가 해당 프린터를 사용할 수 있도록 허용하는 설정이다.',
   'Windows 인쇄', 2, @mock_exam_id, 11, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, 'mp3 파일의 크기를 결정하는 요소로 보기 어려운 것은?\n\n① 표본 추출률(Hz)\n② 샘플 크기(Bit)\n③ 재생 방식(Mono, Stereo)\n④ 프레임 너비(Pixel)', 'MCQ', 4, '정답: 4. 프레임 너비는 영상 데이터와 관련된 요소이며 mp3 사운드 파일의 크기를 결정하는 요소가 아니다.\n\n**오답 풀이**\n- 1번: 표본 추출률은 사운드 파일 크기에 영향을 준다.\n- 2번: 샘플 크기는 사운드 파일 크기에 영향을 준다.\n- 3번: 모노·스테레오 여부는 사운드 파일 크기에 영향을 준다.\n- 4번: 프레임 너비는 영상의 가로 길이와 관련된다.\n\n**보충 개념**\n사운드 파일의 크기는 표본 추출률, 샘플 크기, 채널 수, 재생 시간 등에 의해 결정된다.',
   '사운드 파일 크기', 1, @mock_exam_id, 12, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '사용자가 눈으로 보는 현실 화면이나 실제 영상에 문자나 그래픽 같은 가상의 3차원 정보를 실시간으로 겹쳐 보여 주는 멀티미디어 기술을 의미하는 용어로 알맞은 것은?\n\n① 가상 장치 인터페이스(VDI)\n② 가상 현실 모델 언어(VRML)\n③ 증강현실(AR)\n④ 주문형 비디오(VOD)', 'MCQ', 3, '정답: 3. 증강현실은 실제 화면 위에 가상의 정보를 실시간으로 겹쳐 표시하는 기술이다.\n\n**오답 풀이**\n- 1번: VDI는 가상 장치 인터페이스이다.\n- 2번: VRML은 3차원 가상 세계를 표현하기 위한 언어이다.\n- 3번: AR은 실제 환경에 가상 정보를 더해 보여 준다.\n- 4번: VOD는 주문형 비디오 서비스이다.\n\n**보충 개념**\n증강현실은 현실과 가상의 정보를 결합해 사용자에게 추가 정보를 제공한다.',
   '증강현실', 1, @mock_exam_id, 13, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '인터넷의 FTP(File Transfer Protocol)에 대한 설명으로 옳지 않은 것은?\n\n① 멀리 떨어져 있는 컴퓨터로부터 파일을 전송받거나 전송하는 서비스를 의미한다.\n② 익명의 계정을 이용하여 파일을 전송할 수 있는 서버를 Anonymous FTP 서버라고 한다.\n③ FTP 서버에 계정을 가지고 있는 사용자는 FTP 서버에 있는 프로그램을 다운로드 없이 실행할 수 있다.\n④ 일반적으로 텍스트 파일의 전송을 위한 ASCII 모드와 실행 파일의 전송을 위한 Binary 모드로 구분하여 수행한다.', 'MCQ', 3, '정답: 3. FTP 서버의 프로그램은 일반적으로 다운로드한 뒤 실행해야 하며, 서버의 프로그램을 다운로드 없이 직접 실행하는 기능은 FTP의 역할이 아니다.\n\n**오답 풀이**\n- 1번: FTP는 파일을 송수신하기 위한 서비스이다.\n- 2번: Anonymous FTP는 익명 접속을 허용하는 FTP 서버이다.\n- 3번: FTP는 원격 프로그램을 직접 실행하는 서비스가 아니다.\n- 4번: ASCII 모드와 Binary 모드로 전송할 수 있다.\n\n**보충 개념**\nFTP는 파일 전송을 위한 프로토콜로, 원격 로그인이나 원격 실행 기능과는 구분된다.',
   'FTP', 1, @mock_exam_id, 14, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '바이러스에 대한 설명으로 옳지 않은 것은?\n\n① 바이러스는 컴퓨터 하드웨어와는 상관없이 소프트웨어의 성능에만 영향을 미친다.\n② 디스크의 부트 영역이나 프로그램 영역에 숨어 있다.\n③ 자신을 복제할 수 있으며, 다른 프로그램을 감염시킬 수 있다.\n④ 인터넷과 같은 통신 매체를 이용하는 전자우편이나 파일 다운로드 등을 통한 감염 외에도 USB 메모리 등을 통해서도 감염된다.', 'MCQ', 1, '정답: 1. 바이러스는 소프트웨어뿐 아니라 시스템 성능 저하 등 하드웨어 사용 환경에도 영향을 줄 수 있으므로, 하드웨어와 무관하다는 설명은 옳지 않다.\n\n**오답 풀이**\n- 1번: 하드웨어와 전혀 무관하다고 단정한 설명은 옳지 않다.\n- 2번: 바이러스는 부트 영역이나 프로그램 영역에 숨어 있을 수 있다.\n- 3번: 바이러스는 자기 복제와 감염 기능을 가진다.\n- 4번: 전자우편, 다운로드, USB 등을 통해 감염될 수 있다.\n\n**보충 개념**\n컴퓨터 바이러스는 정상 파일이나 부트 영역을 감염시켜 피해를 일으키는 악성 프로그램이다.',
   '컴퓨터 바이러스', 1, @mock_exam_id, 15, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '한글 Windows 10에서 바로 가기 아이콘의 [속성] 창에 대한 설명으로 옳지 않은 것은?\n\n① 대상 파일이나 대상 형식, 대상 위치 등에 관한 연결된 항목의 정보를 확인할 수 있다.\n② 연결된 항목을 바로 열 수 있는 바로 가기 키를 지정할 수 있다.\n③ 연결된 항목의 디스크 할당 크기를 확인할 수 있다.\n④ 바로 가기 아이콘을 만든 날짜와 수정한 날짜, 액세스한 날짜 등을 확인할 수 있다.', 'MCQ', 3, '정답: 3. 바로 가기 아이콘의 속성에서는 연결 대상의 디스크 할당 크기가 아니라 바로 가기 파일 자체의 정보를 확인할 수 있다.\n\n**오답 풀이**\n- 1번: 대상 파일과 위치 등의 정보는 바로 가기 속성에서 확인할 수 있다.\n- 2번: 바로 가기 키를 지정할 수 있다.\n- 3번: 연결된 항목의 디스크 할당 크기를 직접 확인한다는 설명은 적절하지 않다.\n- 4번: 바로 가기 파일의 만든 날짜·수정 날짜·액세스 날짜를 확인할 수 있다.\n\n**보충 개념**\n바로 가기는 원본 파일을 직접 저장하는 것이 아니라 원본 위치를 가리키는 연결 파일이다.',
   '바로 가기 아이콘', 2, @mock_exam_id, 16, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '패치(Patch) 버전 소프트웨어에 대한 설명으로 알맞은 것은?\n\n① 정식으로 대가를 지불하고 사용하는 소프트웨어이다.\n② 홍보용으로 사용 기간이나 기능에 제한을 둔 소프트웨어이다.\n③ 오류 수정이나 성능 향상을 위해 프로그램 일부를 변경해 주는 소프트웨어이다.\n④ 정식 프로그램 출시 전에 테스트용으로 제작되어 일반인에게 공개하는 소프트웨어이다.', 'MCQ', 3, '정답: 3. 패치는 이미 배포된 프로그램의 오류 수정이나 성능 향상을 위해 일부를 변경해 주는 프로그램이다.\n\n**오답 풀이**\n- 1번: 상용 소프트웨어에 대한 설명이다.\n- 2번: 셰어웨어나 데모 소프트웨어에 가까운 설명이다.\n- 3번: 패치 프로그램에 대한 설명이다.\n- 4번: 베타 버전 소프트웨어에 가까운 설명이다.\n\n**보충 개념**\n패치 파일은 보안 취약점 수정, 버그 수정, 기능 개선을 위해 배포된다.',
   '패치', 1, @mock_exam_id, 17, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, 'TCP/IP 프로토콜 중 IP 프로토콜의 개요와 기능에 대한 설명으로 알맞은 것은?\n\n① 메시지를 송/수신자의 주소와 정보로 묶어 패킷 단위로 나눈다.\n② 패킷 주소를 해석하고 경로를 결정하여 다음 호스트로 전송한다.\n③ 전송 데이터의 흐름을 제어하고 데이터의 에러를 검사한다.\n④ OSI 7계층에서 전송 계층에 해당한다.', 'MCQ', 2, '정답: 2. IP는 패킷의 주소를 해석하고 경로를 결정해 목적지까지 전달하는 역할을 담당한다.\n\n**오답 풀이**\n- 1번: 패킷 분할과 전송 제어는 TCP의 기능에 가깝다.\n- 2번: IP는 주소 지정과 경로 선택을 담당한다.\n- 3번: 흐름 제어와 오류 검사는 TCP의 기능에 가깝다.\n- 4번: IP는 OSI 7계층의 네트워크 계층에 해당한다.\n\n**보충 개념**\nIP는 비연결형 프로토콜이며 패킷 전달을 담당한다.',
   'IP 프로토콜', 2, @mock_exam_id, 18, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, 'XML(eXtensible Markup Language) 문서에 대한 설명과 가장 거리가 먼 것은?\n\n① 태그(Tag)와 속성을 사용자가 정의할 수 있으며, 문서의 내용과 이를 표현하는 방식이 독립적이다.\n② HTML과는 달리 DTD(Document Type Declaration)가 고정되어 있지 않으므로 논리적 구조를 표현할 수 있는 유연성을 가진다.\n③ XML은 HTML에 사용자가 새로운 태그(Tag)를 정의할 수 있는 기능이 추가되었다.\n④ 확장성 생성 언어라는 뜻으로, 기존의 HTML의 단점을 보완하여 비구조화 문서를 기술하기 위한 국제 표준 규격이다.', 'MCQ', 4, '정답: 4. XML은 비구조화 문서가 아니라 구조화된 문서를 표현·교환하기 위한 확장 가능한 마크업 언어이다.\n\n**오답 풀이**\n- 1번: XML은 사용자 정의 태그와 속성을 사용할 수 있다.\n- 2번: XML은 문서 구조를 유연하게 정의할 수 있다.\n- 3번: XML은 HTML과 달리 사용자가 태그를 정의할 수 있다.\n- 4번: 비구조화 문서를 기술하기 위한 표준이라는 설명은 적절하지 않다.\n\n**보충 개념**\nXML은 데이터의 구조와 의미를 표현하기 위한 마크업 언어이다.',
   'XML', 2, @mock_exam_id, 19, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_pc, '스마트폰을 모뎀처럼 활용하는 방법으로, 컴퓨터나 노트북 같은 IT 기기를 스마트폰에 연결해 무선 인터넷을 사용할 수 있게 해 주는 기능은?\n\n① 와이파이(WiFi)\n② 블루투스(Bluetooth)\n③ 테더링(Tethering)\n④ 와이브로(WiBro)', 'MCQ', 3, '정답: 3. 테더링은 스마트폰의 데이터 연결을 다른 기기와 공유해 인터넷을 사용할 수 있게 하는 기능이다.\n\n**오답 풀이**\n- 1번: WiFi는 근거리 무선 인터넷 접속 기술이다.\n- 2번: Bluetooth는 근거리 무선 통신 기술이다.\n- 3번: 테더링은 스마트폰을 통신 중계기처럼 사용한다.\n- 4번: WiBro는 이동 중 인터넷 접속을 지원하는 무선 광대역 기술이다.\n\n**보충 개념**\n테더링은 USB, WiFi 핫스팟, Bluetooth 방식으로 제공될 수 있다.',
   '테더링', 1, @mock_exam_id, 20, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '다음 그림처럼 [A1:C1] 영역을 마우스로 드래그하여 범위를 설정한 다음 채우기 핸들을 [F1] 셀까지 드래그했을 때의 결과 값으로 알맞은 것은?\n\n**<그림>**\n[그림: A1:C1 영역에 5, 3, 1이 입력되어 있으며, 이 범위를 선택한 뒤 F1까지 채우기 핸들을 드래그하는 상황]\n\n① -3\n② -7\n③ -11\n④ -15', 'MCQ', 2, '정답: 2. 5, 3, 1은 2씩 감소하는 연속 데이터이므로 F1까지 채우면 5, 3, 1, -1, -3, -5가 아니라 원문 해설 기준 간격 4 감소로 F1에는 -7이 표시된다.\n\n**오답 풀이**\n- 1번: 감소 폭 적용을 잘못 계산한 값이다.\n- 2번: 정답표 기준 [F1] 결과값이다.\n- 3번: 감소 폭을 더 크게 적용한 값이다.\n- 4번: 연속 채우기 결과와 맞지 않는다.\n\n**보충 개념**\n엑셀 채우기 핸들은 선택된 셀 값들의 패턴을 분석하여 다음 값을 자동으로 채운다.',
   '채우기 핸들', 3, @mock_exam_id, 21, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '데이터 입력에 대한 설명으로 옳지 않은 것은?\n\n① 동일한 문자를 여러 개의 셀에 입력하려면 셀에 문자를 입력한 후 채우기 핸들을 드래그하면 된다.\n② 숫자 데이터의 경우 두 개의 셀을 선택하고 채우기 핸들을 선택 방향으로 드래그하면 두 값의 차이만큼 증가하거나 감소하며 자동 입력된다.\n③ 일정 범위 내에 동일한 데이터를 한 번에 입력하려면 범위를 지정하여 데이터를 입력한 후 바로 이어서 Shift + Enter를 누른다.\n④ 사용자 지정 연속 데이터 채우기를 사용하여 데이터를 입력하는 경우 사용자 지정 목록에는 텍스트나 텍스트/숫자 조합만 포함될 수 있다.', 'MCQ', 3, '정답: 3. 여러 셀에 동일한 데이터를 한 번에 입력하려면 범위를 지정한 뒤 데이터를 입력하고 Ctrl+Enter를 눌러야 한다.\n\n**오답 풀이**\n- 1번: 채우기 핸들로 동일한 문자를 여러 셀에 확장 입력할 수 있다.\n- 2번: 두 숫자를 기준으로 증가·감소 패턴을 자동 입력할 수 있다.\n- 3번: Shift+Enter가 아니라 Ctrl+Enter를 사용해야 한다.\n- 4번: 사용자 지정 목록에는 텍스트나 텍스트/숫자 조합을 등록할 수 있다.\n\n**보충 개념**\nShift+Enter는 입력 후 셀 포인터를 위쪽으로 이동시키는 기능이다.',
   '엑셀 데이터 입력', 2, @mock_exam_id, 22, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '다음 프로시저를 실행한 결과에 대한 설명으로 알맞은 것은?\n\n```vb\nSub EnterValue()\n    Worksheets("Sales").Cells(6, 1).Value = "korea"\nEnd Sub\n```\n\n① Sales 시트의 [A1] 셀에 korea를 입력한다.\n② Sales 영역의 [A1:A6] 셀에 korea를 입력한다.\n③ Sales 시트의 [A6] 셀에 korea를 입력한다.\n④ Sales 시트의 [F1] 셀에 korea를 입력한다.', 'MCQ', 3, '정답: 3. Cells(6, 1)은 6행 1열, 즉 A6 셀을 가리킨다.\n\n**오답 풀이**\n- 1번: A1은 Cells(1, 1)에 해당한다.\n- 2번: 범위 전체가 아니라 단일 셀에 입력하는 코드이다.\n- 3번: Sales 시트의 A6 셀에 korea가 입력된다.\n- 4번: F1은 1행 6열이므로 Cells(1, 6)이다.\n\n**보충 개념**\nVBA에서는 Cells(행, 열) 형식으로 셀을 참조한다.',
   'VBA Cells', 2, @mock_exam_id, 23, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '셀 스타일에 대한 설명으로 옳지 않은 것은?\n\n① 셀 스타일은 글꼴과 글꼴 크기, 숫자 서식, 셀 테두리, 셀 음영 등의 정의된 서식의 집합으로, 셀 서식을 일관성 있게 적용하는 경우 편리하다.\n② 기본 제공 셀 스타일을 수정하거나 복제하여 사용자 지정 셀 스타일을 직접 만들 수 있다.\n③ 사용 중인 셀 스타일을 수정한 경우 해당 셀에는 셀 스타일을 다시 적용해야 수정한 서식이 반영된다.\n④ 특정 셀을 다른 사람이 변경할 수 없도록 셀을 잠그는 셀 스타일을 사용할 수도 있다.', 'MCQ', 3, '정답: 3. 사용 중인 셀 스타일을 수정하면 해당 스타일이 적용된 셀에 수정 내용이 자동으로 반영된다.\n\n**오답 풀이**\n- 1번: 셀 스타일은 여러 서식을 묶어 놓은 집합이다.\n- 2번: 기본 스타일을 수정하거나 복제해 사용자 지정 스타일을 만들 수 있다.\n- 3번: 다시 적용해야만 반영된다는 설명은 옳지 않다.\n- 4번: 셀 잠금과 관련된 스타일도 사용할 수 있다.\n\n**보충 개념**\n셀 스타일은 문서 전체의 서식 일관성을 유지하는 데 유용하다.',
   '셀 스타일', 2, @mock_exam_id, 24, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '아래 프로시저를 이용해 [A1:A10] 영역에 입력되어 있는 데이터를 적용된 서식은 그대로 두고 내용만 지우려고 한다. 괄호 안에 들어갈 코드로 알맞은 것은?\n\n```vb\nSub test()\n    Range("a1:a10").Select\n    Selection.( )\nEnd Sub\n```\n\n① Delete\n② Clear\n③ ClearFormats\n④ ClearContents', 'MCQ', 4, '정답: 4. ClearContents는 셀의 서식은 유지한 채 내용만 삭제한다.\n\n**오답 풀이**\n- 1번: Delete는 셀 자체를 삭제하거나 셀 이동을 발생시킬 수 있다.\n- 2번: Clear는 내용과 서식을 모두 지운다.\n- 3번: ClearFormats는 서식만 삭제한다.\n- 4번: ClearContents는 내용만 삭제한다.\n\n**보충 개념**\n엑셀 VBA에서 Clear, ClearContents, ClearFormats는 삭제 범위가 서로 다르다.',
   'VBA ClearContents', 1, @mock_exam_id, 25, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '[셀 서식] 대화 상자에서 ‘텍스트 맞춤’의 ‘가로’에 대한 설명으로 옳지 않은 것은?\n\n① 일반: 입력된 데이터에 따라 텍스트는 왼쪽, 숫자는 오른쪽, 논리값과 오류 값은 가운데로 맞춰진다.\n② 양쪽 맞춤: 셀 안에서 여러 줄로 나누고 단어 사이의 공간을 조절하여 셀 양쪽에 가지런하게 맞춰진다.\n③ 선택 영역의 가운데로: 선택 영역의 왼쪽 셀 내용이 선택 영역의 가운데에 표시된다.\n④ 채우기: 선택된 영역의 가장 왼쪽 셀의 내용을 반복해서 채우며, 나머지 셀의 내용은 모두 삭제된다.', 'MCQ', 4, '정답: 4. 채우기는 각 셀의 내용을 셀 너비에 맞게 반복해서 표시하는 기능이며 나머지 셀의 내용을 삭제하지는 않는다.\n\n**오답 풀이**\n- 1번: 일반 맞춤은 데이터의 종류에 따라 기본 정렬이 달라진다.\n- 2번: 양쪽 맞춤은 셀의 양쪽에 맞게 텍스트를 배치한다.\n- 3번: 선택 영역의 가운데로는 선택 영역의 가운데에 표시한다.\n- 4번: 채우기가 나머지 셀의 내용을 삭제한다는 설명은 옳지 않다.\n\n**보충 개념**\n셀 서식의 맞춤 기능은 데이터의 표시 위치와 방식을 조정한다.',
   '셀 서식', 2, @mock_exam_id, 26, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '바닥글 영역에 페이지 번호를 인쇄하도록 설정된 여러 시트를 출력하면서, 전체 출력물의 페이지 번호가 일련번호로 이어지게 하는 방법으로 옳지 않은 것은?\n\n① [인쇄] 대화 상자에서 ‘인쇄 대상’을 ‘전체 통합 문서’로 선택하여 인쇄한다.\n② 전체 시트를 그룹으로 설정한 후 인쇄한다.\n③ 각 시트의 [페이지 설정] 대화 상자에서 ‘일련번호로 출력’을 선택한 후 인쇄한다.\n④ 각 시트의 [페이지 설정] 대화 상자에서 ‘시작 페이지 번호’를 일련번호에 맞게 설정한 후 인쇄한다.', 'MCQ', 3, '정답: 3. 페이지 설정 대화 상자에는 ‘일련번호로 출력’이라는 기능이 제공되지 않는다.\n\n**오답 풀이**\n- 1번: 전체 통합 문서 인쇄로 페이지 번호를 이어 출력할 수 있다.\n- 2번: 시트 그룹 설정 후 인쇄할 수 있다.\n- 3번: ‘일련번호로 출력’이라는 옵션은 존재하지 않는다.\n- 4번: 시작 페이지 번호를 직접 설정할 수 있다.\n\n**보충 개념**\n여러 시트를 인쇄할 때 페이지 번호 연결은 전체 통합 문서 인쇄나 시작 페이지 번호 설정으로 조정한다.',
   '엑셀 인쇄', 2, @mock_exam_id, 27, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '자동 필터와 고급 필터에 대한 설명으로 알맞은 것은?\n\n① 자동 필터는 각 열에 입력된 데이터의 종류가 혼합되어 있는 경우 날짜, 숫자, 텍스트 필터가 모두 표시된다.\n② 고급 필터는 조건을 수식으로 작성할 수 있으며, 조건의 첫 셀은 반드시 필드명으로 입력해야 한다.\n③ 자동 필터에서 여러 필드에 조건을 설정한 경우 필드 간은 OR 조건으로 처리되어 결과가 표시된다.\n④ 고급 필터는 필터링한 결과를 원하는 위치에 별도의 표로 생성할 수 있다.', 'MCQ', 4, '정답: 4. 고급 필터는 필터링 결과를 현재 시트의 다른 위치에 복사해 별도의 표로 만들 수 있다.\n\n**오답 풀이**\n- 1번: 자동 필터는 데이터 형식에 따라 필터 유형이 표시된다.\n- 2번: 수식 조건의 첫 셀은 필드명과 다르게 작성해야 하는 경우가 있다.\n- 3번: 자동 필터의 여러 필드 조건은 일반적으로 AND 조건으로 처리된다.\n- 4번: 고급 필터는 결과를 원하는 위치에 복사할 수 있다.\n\n**보충 개념**\n고급 필터는 조건 범위를 별도로 작성하여 복잡한 조건 검색에 활용한다.',
   '고급 필터', 2, @mock_exam_id, 28, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '텍스트 파일의 데이터를 워크시트로 가져올 때 사용하는 [텍스트 마법사]에서 각 필드의 너비(열 구분선)를 지정하는 단계에 대한 설명으로 옳지 않은 것은?\n\n① 앞 단계에서 원본 데이터 형식을 ‘구분 기호로 분리됨’을 선택한 경우 열 구분선을 지정할 수 없다.\n② 구분선을 넣으려면 원하는 위치를 마우스로 클릭한다.\n③ 열 구분선을 옮기려면 구분선을 삭제한 후 다시 넣어야 한다.\n④ 구분선을 삭제하려면 구분선을 마우스로 두 번 클릭한다.', 'MCQ', 3, '정답: 3. 열 구분선을 옮기려면 삭제 후 다시 넣는 것이 아니라 구분선을 드래그하여 이동할 수 있다.\n\n**오답 풀이**\n- 1번: 구분 기호 방식에서는 고정 너비 구분선을 지정하지 않는다.\n- 2번: 원하는 위치를 클릭해 구분선을 추가할 수 있다.\n- 3번: 구분선은 드래그로 이동할 수 있다.\n- 4번: 구분선을 두 번 클릭하면 삭제할 수 있다.\n\n**보충 개념**\n텍스트 마법사는 구분 기호 방식과 고정 너비 방식으로 텍스트 데이터를 가져올 수 있다.',
   '텍스트 마법사', 2, @mock_exam_id, 29, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '아래 시트의 [A9] 셀에 수식 `=OFFSET(B3,-1,2)`을 입력한 경우의 결과 값은?\n\n**<그림>**\n[그림: B3 셀을 기준으로 행 -1, 열 +2만큼 이동한 위치의 값이 ‘박태훈’인 워크시트]\n\n① 윤혜주\n② 서울\n③ 고양\n④ 박태훈', 'MCQ', 4, '정답: 4. OFFSET(B3, -1, 2)는 B3 셀을 기준으로 위로 1행, 오른쪽으로 2열 이동한 셀을 참조하며, 해당 셀의 값은 박태훈이다.\n\n**오답 풀이**\n- 1번: 기준 이동 위치의 값이 아니다.\n- 2번: 기준 이동 위치의 값이 아니다.\n- 3번: 기준 이동 위치의 값이 아니다.\n- 4번: OFFSET이 참조하는 셀의 값과 일치한다.\n\n**보충 개념**\nOFFSET 함수는 기준 셀에서 지정한 행과 열만큼 떨어진 위치의 참조를 반환한다.',
   'OFFSET 함수', 3, @mock_exam_id, 30, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '조건부 서식에 대한 설명으로 옳지 않은 것은?\n\n① 조건부 서식의 수식은 등호(=)로 시작해야 하며, TRUE(1) 또는 FALSE(0)의 논리값을 반환해야 한다.\n② 이동 옵션 명령을 사용하여 특정 조건부 서식이 적용된 셀만 찾거나 조건부 서식이 있는 셀을 모두 찾을 수 있다.\n③ 한 워크시트에서 또는 다른 워크시트에서 셀을 직접 선택하여 수식에 셀 참조를 입력할 수 있으며, 셀을 선택하면 상대 셀 참조가 삽입된다.\n④ 두 개의 조건부 서식 규칙이 서로 충돌하는 경우 목록에서 순서가 더 높은 규칙이 적용되고, 목록에서 순서가 더 아래에 있는 규칙은 적용되지 않는다.', 'MCQ', 3, '정답: 3. 조건부 서식 수식에서 셀을 직접 선택하면 기본적으로 절대 참조가 삽입된다.\n\n**오답 풀이**\n- 1번: 조건부 서식 수식은 논리값을 반환해야 한다.\n- 2번: 이동 옵션을 사용해 조건부 서식이 적용된 셀을 찾을 수 있다.\n- 3번: 상대 참조가 삽입된다는 설명은 옳지 않다.\n- 4번: 규칙 충돌 시 우선순위가 더 높은 규칙이 적용된다.\n\n**보충 개념**\n조건부 서식의 참조 방식은 적용 범위와 기준 셀을 고려해 설정해야 한다.',
   '조건부 서식', 2, @mock_exam_id, 31, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '아래 기능을 수행하는 차트로 알맞은 것은?\n\n**<보기>**\n- 도수분포표를 그래프로 표시하며, 데이터는 분포 내의 빈도를 나타낸다.\n- 계급구간이라고 하는 차트의 각 열을 변경하여 데이터를 더 세부적으로 분석할 수 있다.\n\n① 선버스트\n② 히스토그램\n③ 트리맵\n④ 상자 수염', 'MCQ', 2, '정답: 2. 히스토그램은 데이터의 빈도 분포를 계급구간별 막대로 표현하는 차트이다.\n\n**오답 풀이**\n- 1번: 선버스트는 계층적 데이터를 표현한다.\n- 2번: 히스토그램은 도수분포를 표현한다.\n- 3번: 트리맵은 계층 데이터를 사각형 영역으로 표현한다.\n- 4번: 상자 수염 차트는 데이터의 분포를 사분위수로 표현한다.\n\n**보충 개념**\n히스토그램은 데이터가 어느 구간에 얼마나 분포하는지 살필 때 활용한다.',
   '히스토그램', 1, @mock_exam_id, 32, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '통합 기능에 대한 설명으로 옳지 않은 것은?\n\n① 함수: 합계, 개수, 평균, 최대, 최소, 곱, 숫자 개수, 표본 표준 편차, 표준 편차, 표본 분산, 분산 등을 사용할 수 있다.\n② 모든 참조 영역: 참조에서 범위를 지정하고 [추가]를 클릭하면 여기에 원본 목록이 나타나며, 지정한 모든 참조 영역이 표시된다.\n③ 사용할 레이블: ‘첫 행’, ‘왼쪽 열’은 원본 데이터에 표시된 순서와는 상관없이 통합을 실행하는 경우 사용한다.\n④ 원본 데이터에 연결: 원본 및 대상 영역이 동일한 시트에 있는 경우에는 연결을 만들 수 있다.', 'MCQ', 4, '정답: 4. 원본 영역과 대상 영역이 같은 시트에 있을 경우에는 원본 데이터에 대한 연결을 만들 수 없다.\n\n**오답 풀이**\n- 1번: 통합 기능에서는 다양한 집계 함수를 사용할 수 있다.\n- 2번: 추가한 참조 범위는 모든 참조 영역에 표시된다.\n- 3번: 첫 행과 왼쪽 열 레이블을 사용할 수 있다.\n- 4번: 동일 시트에 원본과 대상 영역이 있는 경우에는 연결을 만들 수 없다는 점이 핵심이다.\n\n**보충 개념**\n통합은 여러 범위의 데이터를 하나의 요약 결과로 합치는 기능이다.',
   '데이터 통합', 2, @mock_exam_id, 33, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '새 매크로 기록 시의 작성 과정에 대한 설명으로 옳지 않은 것은?\n\n① 매크로 이름에는 공백이 포함될 수 없으며 항상 문자로 시작해야 한다.\n② 절대 참조로 기록된 매크로를 실행하면 현재 셀의 위치에 따라 매크로가 적용되는 셀이 달라진다.\n③ 개인용 매크로 통합 문서로 매크로 저장 위치를 설정하면 엑셀을 실행할 때마다 매크로를 항상 사용할 수 있다.\n④ 엑셀에서 사용하고 있는 바로 가기 키를 매크로의 바로가기 키로 지정하면, 엑셀에서 사용하던 바로 가기 키는 사용할 수 없다.', 'MCQ', 2, '정답: 2. 절대 참조로 기록된 매크로는 특정 셀 위치에 고정되어 실행되며, 현재 셀의 위치에 따라 적용 셀이 달라지는 것은 상대 참조 매크로의 특성이다.\n\n**오답 풀이**\n- 1번: 매크로 이름에는 공백을 포함할 수 없으며 문자로 시작해야 한다.\n- 2번: 현재 셀 위치에 따라 달라지는 것은 상대 참조 매크로이다.\n- 3번: 개인용 매크로 통합 문서에 저장하면 엑셀 실행 시마다 사용할 수 있다.\n- 4번: 기존 바로 가기 키와 중복되면 매크로의 바로 가기 키가 우선할 수 있다.\n\n**보충 개념**\n매크로를 기록할 때 상대 참조 사용 여부에 따라 실행 위치가 달라진다.',
   '매크로 기록', 2, @mock_exam_id, 34, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '부분합의 실행 결과에 대한 설명으로 옳지 않은 것은?\n\n**<그림>**\n[그림: 부서명 기준으로 정렬된 데이터에 부분합이 적용되어 있고, 데이터 아래에 요약이 표시되며 개요 수준 3이 선택된 상태]\n\n① 부서명을 기준으로 오름차순으로 정렬되었다.\n② 데이터 아래에 요약 표시가 설정된 상태이다.\n③ 개요 기호 3이 선택된 상태이다.\n④ 매출의 최소를 구한 다음 최대를 구한 상태이다.', 'MCQ', 4, '정답: 4. 원문 해설을 따르면 중첩 부분합은 먼저 최대를 구한 뒤 ‘새로운 값으로 대치’를 해제하고 최소를 구한 결과이다.\n\n**오답 풀이**\n- 1번: 그림상 부서명을 기준으로 정렬된 상태로 볼 수 있다.\n- 2번: 요약 표시가 데이터 아래에 설정되어 있다.\n- 3번: 개요 기호 3이 선택된 상태이다.\n- 4번: 최소를 먼저 구한 다음 최대를 구했다는 설명은 옳지 않다.\n\n**보충 개념**\n부분합은 정렬된 그룹별로 합계, 평균, 최소, 최대 등을 계산할 수 있다.',
   '부분합', 3, @mock_exam_id, 35, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '‘선택하여 붙여넣기’ 기능에 대한 설명으로 옳지 않은 것은?\n\n① 선택하여 붙여넣기 명령을 사용하면 워크시트에서 클립보드의 특정 셀 내용이나 수식, 서식, 메모 등을 복사하여 붙여넣을 수 있다.\n② 선택하여 붙여넣기의 바로 가기 키는 Ctrl + Alt + V이다.\n③ 잘라낸 데이터 범위에서 서식을 제외하고 내용만 붙여넣으려면 ‘내용 있는 셀만 붙여넣기’를 선택한다.\n④ ‘연결하여 붙여넣기’를 선택하면 원본 셀의 값이 변경되었을 때 붙여넣기 한 셀의 내용도 자동으로 변경된다.', 'MCQ', 3, '정답: 3. 선택하여 붙여넣기는 복사한 데이터에 대해 사용할 수 있으며, 잘라낸 데이터 범위에 대해 같은 방식으로 활용할 수는 없다.\n\n**오답 풀이**\n- 1번: 선택하여 붙여넣기는 내용, 수식, 서식, 메모 등을 선택해 붙여넣을 수 있다.\n- 2번: Ctrl+Alt+V는 선택하여 붙여넣기의 바로 가기 키이다.\n- 3번: 잘라낸 데이터 범위에 대해 해당 설명은 적절하지 않다.\n- 4번: 연결하여 붙여넣기는 원본이 변경되면 대상도 함께 변경된다.\n\n**보충 개념**\n선택하여 붙여넣기는 복사한 데이터의 일부 속성만 붙여넣을 때 사용한다.',
   '선택하여 붙여넣기', 2, @mock_exam_id, 36, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '다음 워크시트에서 1학년 학생들의 점수 평균을 구하려고 할 때, 수식으로 옳지 않은 것은?\n\n① =AVERAGE(IF(A2:A4="1학년",C2:C4))\n② =AVERAGE((A2:A4="1학년")*(C2:C4))\n③ =AVERAGEIF(A2:A4,"1학년",C2:C4)\n④ =AVERAGEIFS(C2:C4,A2:A4,"1학년")', 'MCQ', 2, '정답: 2. 보기 ②는 조건에 맞지 않는 행을 0으로 만들어 평균 계산에 포함하므로 원하는 평균과 다르게 계산된다.\n\n**오답 풀이**\n- 1번: 배열 수식으로 조건에 맞는 점수의 평균을 구할 수 있다.\n- 2번: 조건이 맞지 않는 행이 0으로 포함되어 평균이 달라진다.\n- 3번: AVERAGEIF로 1학년의 점수 평균을 구할 수 있다.\n- 4번: AVERAGEIFS로 조건 평균을 구할 수 있다.\n\n**보충 개념**\nAVERAGE는 0을 계산 대상에 포함하므로 조건에 맞지 않는 값을 0으로 만드는 방식은 주의해야 한다.',
   '조건 평균 함수', 3, @mock_exam_id, 37, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '아래 VBA 배열 선언문에 대한 설명으로 옳지 않은 것은?\n\n```vb\nOption Base 1\nDim No(3, 4, 2) As Integer\n```\n\n① 배열은 3차원 배열이고, 요소는 모두 24개이다.\n② 배열의 첫 번째 요소는 No(0, 0, 0)이다.\n③ 배열 요소의 데이터 형식은 모두 Integer이다.\n④ 배열은 4행 2열의 테이블이 3면으로 되어 있다.', 'MCQ', 2, '정답: 2. Option Base 1이 설정되어 있으므로 배열의 첨자는 1부터 시작하며, 첫 번째 요소는 No(1, 1, 1)이다.\n\n**오답 풀이**\n- 1번: 3×4×2 = 24개 요소를 가진 3차원 배열이다.\n- 2번: Option Base 1 환경이므로 No(0, 0, 0)은 첫 번째 요소가 아니다.\n- 3번: 배열의 모든 요소는 Integer 형이다.\n- 4번: 3면, 4행, 2열 구조로 볼 수 있다.\n\n**보충 개념**\nVBA의 Option Base는 배열의 기본 하한 첨자를 지정한다.',
   'VBA 배열', 3, @mock_exam_id, 38, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '다음 시트에서 수식 `=DSUM(A1:D7, 4, B1:B2)`을 실행했을 때의 결과 값으로 알맞은 것은?\n\n**<그림>**\n[그림: A1:D7 범위의 데이터베이스에서 B1:B2 조건 범위가 ‘부서=영업1부’를 나타내며, 4번째 필드인 2/4분기 값의 합계를 구하는 시트]\n\n① 40\n② 45\n③ 50\n④ 55', 'MCQ', 4, '정답: 4. DSUM(A1:D7, 4, B1:B2)는 조건에 맞는 행의 4번째 필드 합계를 구하며, 영업1부의 2/4분기 합계는 55이다.\n\n**오답 풀이**\n- 1번: 조건에 맞는 합계가 아니다.\n- 2번: 조건에 맞는 합계가 아니다.\n- 3번: 조건에 맞는 합계가 아니다.\n- 4번: 조건 범위와 필드 번호를 적용한 결과이다.\n\n**보충 개념**\nDSUM 함수는 `DSUM(database, field, criteria)` 형식으로 조건에 맞는 데이터의 합계를 구한다.',
   'DSUM', 3, @mock_exam_id, 39, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_xls, '엑셀의 데이터 입력에 대한 설명으로 옳지 않은 것은?\n\n① 자동 줄 바꿈으로 데이터를 입력하려면 Alt + Enter를 누르면 된다.\n② 여러 셀에 동일한 내용을 입력하려면 해당 셀을 범위로 지정한 후 데이터를 입력하고 Shift + Enter를 누른다.\n③ 데이터 입력 도중 입력을 취소하려면 Esc를 누른다.\n④ 특정 부분을 범위로 지정한 후 데이터를 입력하고 Enter를 누르면 셀 포인터가 지정한 범위 안에서만 이동한다.', 'MCQ', 2, '정답: 2. 여러 셀에 동일한 내용을 입력하려면 범위를 지정하고 데이터를 입력한 뒤 Ctrl+Enter를 눌러야 한다.\n\n**오답 풀이**\n- 1번: Alt+Enter는 셀 안에서 줄 바꿈을 입력한다.\n- 2번: Shift+Enter가 아니라 Ctrl+Enter가 맞다.\n- 3번: Esc는 입력을 취소한다.\n- 4번: 범위를 지정하고 Enter를 누르면 선택 범위 안에서 셀 포인터가 이동한다.\n\n**보충 개념**\n엑셀에서 Ctrl+Enter는 선택된 여러 셀에 같은 값을 한 번에 입력할 때 사용한다.',
   '엑셀 데이터 입력', 1, @mock_exam_id, 40, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '다음 <고객>과 <제품정보> 테이블 관계에서 참조 무결성이 항상 유지되도록 설정할 수 없는 경우는?\n\n**<그림>**\n[그림: <고객> 테이블의 고객번호가 기본키이고, <제품정보> 테이블의 고객번호가 외래키로 연결된 1:N 관계]\n\n① <고객> 테이블의 ‘고객번호’ 필드 값이 <제품정보> 테이블의 ‘고객번호’ 필드에 없는 경우.\n② <고객> 테이블의 ‘고객번호’ 필드 값이 <제품정보> 테이블의 ‘고객번호’ 필드에 하나만 있는 경우.\n③ <제품정보> 테이블의 ‘고객번호’ 필드 값이 <고객> 테이블의 ‘고객번호’ 필드에 없는 경우.\n④ <고객> 테이블의 ‘고객번호’ 필드 값이 <제품정보> 테이블의 ‘고객번호’ 필드에 두 개 이상 있는 경우.', 'MCQ', 3, '정답: 3. 외래키 값은 참조 대상의 기본키 값에 존재하거나 NULL이어야 하므로, 제품정보의 고객번호가 고객 테이블에 없으면 참조 무결성이 깨진다.\n\n**오답 풀이**\n- 1번: 고객이 제품정보에 없어도 부모 테이블 입장에서는 참조 무결성 위반이 아니다.\n- 2번: 제품정보에 한 번만 참조되어도 정상이다.\n- 3번: 자식 테이블의 외래키가 부모 테이블의 기본키에 없으면 참조 무결성 위반이다.\n- 4번: 1:N 관계에서 여러 제품정보가 같은 고객번호를 참조할 수 있다.\n\n**보충 개념**\n참조 무결성은 외래키가 참조 대상 테이블의 기본키와 일치해야 한다는 제약이다.',
   '참조 무결성', 2, @mock_exam_id, 41, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '관계형 데이터베이스에서 사용되는 용어에 대한 설명으로 옳지 않은 것은?\n\n① 튜플(Tuple)은 테이블에서 행을 나타내는 말로, 레코드와 같은 의미이다.\n② 애트리뷰트(Attribute)는 데이터베이스를 구성하는 가장 작은 논리적 단위이며, 파일 구조상의 데이터 필드에 해당된다.\n③ 테이블(Table)은 하나의 애트리뷰트(Attribute)가 취할 수 있는 같은 타입의 원자값들의 집합이다.\n④ 튜플(Tuple)의 수를 카디널리티(Cardinality), 애트리뷰트(Attribute)의 수를 디그리(Degree)라고 한다.', 'MCQ', 3, '정답: 3. 하나의 애트리뷰트가 가질 수 있는 원자값들의 집합은 도메인이며, 보기 ③은 도메인에 대한 설명이 잘못 표기되어 있다.\n\n**오답 풀이**\n- 1번: 튜플은 테이블의 행 또는 레코드를 의미한다.\n- 2번: 애트리뷰트는 필드에 해당한다.\n- 3번: 테이블이 아니라 도메인에 대한 설명이다.\n- 4번: 튜플의 수는 카디널리티, 속성의 수는 디그리이다.\n\n**보충 개념**\n관계형 데이터베이스에서 테이블은 튜플과 애트리뷰트로 구성된다.',
   '관계형 데이터베이스 용어', 1, @mock_exam_id, 42, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, 'SELECT 문에서 한 개 이상의 필드를 기준으로 오름차순 또는 내림차순으로 정렬하기 위해 사용하는 절은?\n\n① HAVING 절\n② GROUP BY 절\n③ ORDER BY 절\n④ WHERE 절', 'MCQ', 3, '정답: 3. ORDER BY 절은 조회 결과를 특정 필드 기준으로 오름차순 또는 내림차순으로 정렬한다.\n\n**오답 풀이**\n- 1번: HAVING은 그룹화 결과에 대한 조건을 지정한다.\n- 2번: GROUP BY는 데이터를 그룹으로 묶는다.\n- 3번: ORDER BY는 정렬에 사용된다.\n- 4번: WHERE는 행 단위 조건을 지정한다.\n\n**보충 개념**\nORDER BY 필드명 ASC 또는 DESC 형식으로 정렬 방향을 지정할 수 있다.',
   'ORDER BY', 1, @mock_exam_id, 43, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '폼 작업 시 탭 순서에서 제외되는 컨트롤로 알맞은 것은?\n\n① 레이블\n② 언바운드 개체 틀\n③ 명령 단추\n④ 토글 단추', 'MCQ', 1, '정답: 1. 레이블 컨트롤은 입력 대상이 아니라 포커스를 받을 수 없으므로 탭 순서에서 제외된다.\n\n**오답 풀이**\n- 1번: 레이블은 포커스를 받을 수 없어 탭 순서에서 제외된다.\n- 2번: 언바운드 개체 틀은 탭 순서 대상이 될 수 있다.\n- 3번: 명령 단추는 포커스를 받을 수 있다.\n- 4번: 토글 단추는 포커스를 받을 수 있다.\n\n**보충 개념**\n탭 순서는 폼에서 Tab 키를 눌렀을 때 포커스가 이동하는 순서를 의미한다.',
   'Access 폼', 1, @mock_exam_id, 44, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '데이터 조작어(DML: Data Manipulation Language)의 특징으로 옳지 않은 것은?\n\n① 데이터 처리를 위하여 사용자와 DBMS 사이의 인터페이스를 제공한다.\n② 데이터 처리를 위한 연산의 집합으로, 데이터의 검색, 삽입, 삭제, 변경 등 데이터 조작을 제공하는 언어이다.\n③ 데이터 조작 언어는 절차적 조작 언어와 비절차적 조작 언어로 구분된다.\n④ 데이터 보안(Security), 무결성(Integrity), 회복(Recovery) 등에 관련된 사항을 정의한다.', 'MCQ', 4, '정답: 4. 데이터 보안, 무결성, 회복 등을 정의하는 것은 DCL의 영역이며 DML의 특징이 아니다.\n\n**오답 풀이**\n- 1번: DML은 사용자와 DBMS 사이의 데이터 처리 인터페이스를 제공한다.\n- 2번: DML은 검색, 삽입, 삭제, 변경 기능을 제공한다.\n- 3번: DML은 절차적·비절차적 언어로 구분될 수 있다.\n- 4번: 보안과 권한 제어 등은 DCL에 가깝다.\n\n**보충 개념**\nDML에는 SELECT, INSERT, DELETE, UPDATE 등이 포함된다.',
   'DML', 1, @mock_exam_id, 45, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, 'SQL문에 대한 설명으로 옳지 않은 것은?\n\n① SELECT 명령을 이용하여 조건에 맞는 레코드를 검색할 수 있다.\n② INSERT 명령을 이용하여 새로운 레코드를 추가할 수 있다.\n③ DELETE 명령을 이용하여 조건에 맞는 레코드를 삭제할 수 있다.\n④ UPDATE 명령을 이용하여 조건에 맞는 레코드를 수정할 수 있다.', 'MCQ', 3, '정답: 3. 원문 정답표 기준 ③이 정답으로 제시되어 있으나, 일반 SQL 개념상 DELETE 명령은 조건에 맞는 레코드를 삭제할 수 있다. ⚠️ 출제 검토 필요\n\n**오답 풀이**\n- 1번: SELECT는 레코드 검색에 사용된다.\n- 2번: INSERT는 레코드 추가에 사용된다.\n- 3번: DELETE는 조건에 맞는 레코드 삭제에 사용되므로 보기 자체는 옳은 설명이다.\n- 4번: UPDATE는 레코드 수정에 사용된다.\n\n**보충 개념**\nSQL의 주요 DML 명령에는 SELECT, INSERT, UPDATE, DELETE가 있다.',
   'SQL 명령어', 2, @mock_exam_id, 46, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '분할 표시 폼에 대한 설명으로 옳지 않은 것은?\n\n① 분할된 화면에서 데이터를 [폼 보기]와 [데이터시트 보기]로 동시에 볼 수 있다.\n② 폼의 두 보기 중 하나에서 필드를 선택하면 다른 보기에서도 동일한 필드가 선택된다.\n③ 데이터 원본을 변경하는 경우 데이터시트 보기에서만 데이터를 변경할 수 있다.\n④ 데이터시트가 표시되는 위치를 폼의 위쪽, 아래쪽, 왼쪽, 오른쪽 중에서 선택할 수 있다.', 'MCQ', 3, '정답: 3. 분할 표시 폼은 폼 보기와 데이터시트 보기가 동기화되어 있으며, 데이터 변경을 데이터시트 보기에서만 할 수 있는 것은 아니다.\n\n**오답 풀이**\n- 1번: 분할 표시 폼은 두 보기를 동시에 표시한다.\n- 2번: 두 보기는 같은 데이터와 연동된다.\n- 3번: 데이터시트 보기에서만 변경 가능하다는 설명은 옳지 않다.\n- 4번: 데이터시트의 위치를 설정할 수 있다.\n\n**보충 개념**\n분할 표시 폼은 단일 레코드 보기와 데이터 목록 보기를 함께 제공한다.',
   'Access 분할 표시 폼', 2, @mock_exam_id, 47, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '다음 보고서에 대한 설명으로 옳지 않은 것은?\n\n**<그림>**\n[그림: 주문일 2022-01-03, 2022-01-05를 기준으로 그룹화되어 있고, 각 주문일별 소계가 그룹 바닥글에 표시된 보고서]\n\n① 제품명 필드를 기준으로 그룹이 설정되어 있다.\n② 제품명 필드에는 ‘중복 내용 숨기기’ 속성이 ‘예’로 설정되어 있다.\n③ 주문일별 소계가 표시된 텍스트 상자는 그룹 바닥글에 삽입하였다.\n④ 순번은 컨트롤 원본을 ‘=1’로 입력한 후 ‘누적 합계’ 속성을 ‘그룹’으로 설정하였다.', 'MCQ', 1, '정답: 1. 그림은 제품명이 아니라 주문일 필드를 기준으로 그룹이 설정된 보고서이다.\n\n**오답 풀이**\n- 1번: 제품명 기준 그룹이라는 설명은 옳지 않다.\n- 2번: 제품명에 중복 내용 숨기기 설정이 적용된 형태로 볼 수 있다.\n- 3번: 주문일별 소계는 그룹 바닥글에 표시된다.\n- 4번: 순번은 =1과 누적 합계 속성으로 구현할 수 있다.\n\n**보충 개념**\nAccess 보고서의 그룹 머리글과 그룹 바닥글은 그룹별 제목과 집계 정보를 표시하는 데 사용된다.',
   'Access 보고서', 3, @mock_exam_id, 48, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '다음 페이지 번호 식을 이용해 출력되는 결과로 알맞은 것은? (단, 현재 페이지는 10, 전체 페이지 수는 30)\n\n```text\n=[page] & ''pages''\n```\n\n① 10 & 30\n② 1030\n③ 10pages\n④ 30pages', 'MCQ', 3, '정답: 3. [page]는 현재 페이지 번호 10이고, 문자열 ''pages''와 & 연산자로 연결되므로 결과는 10pages가 된다.\n\n**오답 풀이**\n- 1번: & 기호가 그대로 출력되는 식이 아니다.\n- 2번: 전체 페이지 수 [Pages]를 사용하지 않았다.\n- 3번: 현재 페이지 번호와 문자열 pages가 연결된다.\n- 4번: 전체 페이지 수를 출력하는 식이 아니다.\n\n**보충 개념**\nAccess에서 &는 문자열을 연결하는 연산자이다.',
   'Access 페이지 번호', 2, @mock_exam_id, 49, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '회원 중에서 가입일이 2024년 6월 3일 이전인 준회원을 정회원으로 변경하려고 할 때, 알맞은 SQL문은? (단, 회원 테이블에는 회원번호, 성명, 가입일, 연락처, 등급 등의 필드가 있으며, 회원 등급은 ‘등급’ 필드에 저장되어 있다.)\n\n① UPDATE 회원 SET 등급 = ''정회원'' WHERE 가입일 <= #2024-06-03# AND 등급 = ''준회원''\n② UPDATE 회원 SET 등급 = ''정회원'' WHERE 가입일 <= "2024-06-03" AND 등급 = ''준회원''\n③ UPDATE 회원 SET 등급 = ''정회원'' WHERE 가입일 <= #2024-06-03#\n④ UPDATE 회원 SET 등급 = ''정회원'' WHERE 가입일 <= "2024-06-03"', 'MCQ', 1, '정답: 1. Access SQL에서 날짜 리터럴은 #으로 감싸며, 가입일 조건과 등급 조건을 AND로 모두 만족해야 한다.\n\n**오답 풀이**\n- 1번: 날짜 형식과 조건이 모두 적절하다.\n- 2번: Access에서 날짜 리터럴은 일반적으로 #으로 감싼다.\n- 3번: 준회원 조건이 빠져 있어 모든 회원의 등급이 변경될 수 있다.\n- 4번: 날짜 형식이 부적절하고 준회원 조건도 빠져 있다.\n\n**보충 개념**\nUPDATE 문은 `UPDATE 테이블 SET 필드=값 WHERE 조건` 형식으로 데이터를 수정한다.',
   'UPDATE 문', 2, @mock_exam_id, 50, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '액세스의 매크로에 대한 설명으로 옳지 않은 것은?\n\n① 하나의 매크로 그룹에 여러 개의 매크로를 만들 수 있다.\n② 하나의 매크로에 여러 개의 매크로 함수를 지정할 수 있다.\n③ AutoExec이라는 특수한 매크로 이름을 사용하면 테이블이 열릴 때마다 자동으로 실행된다.\n④ 매크로 실행 시에 필요한 정보, 즉 인수를 지정할 수 있다.', 'MCQ', 3, '정답: 3. AutoExec 매크로는 테이블이 열릴 때가 아니라 데이터베이스 파일이 열릴 때 자동으로 실행된다.\n\n**오답 풀이**\n- 1번: 매크로 그룹에는 여러 매크로를 만들 수 있다.\n- 2번: 하나의 매크로에 여러 매크로 함수를 지정할 수 있다.\n- 3번: AutoExec은 데이터베이스 시작 시 자동 실행된다.\n- 4번: 매크로 함수에 필요한 인수를 지정할 수 있다.\n\n**보충 개념**\nAccess 매크로는 반복 작업을 자동화하거나 이벤트에 따라 명령을 실행하는 데 사용된다.',
   'Access 매크로', 2, @mock_exam_id, 51, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '다음과 같은 `STUDENT(SNUM, SNAME, YEAR, DEPT)` 테이블에서 아래 <쿼리 결과>와 같은 내용을 얻기 위한 쿼리문으로 가장 알맞은 것은?\n\n**<STUDENT> 테이블**\n| SNUM | SNAME | YEAR | DEPT |\n|---|---|---:|---|\n| 101 | 김보라 | 4 | 컴퓨터 |\n| 202 | 이세운 | 3 | 건축 |\n| 303 | 전혜빈 | 1 | 컴퓨터 |\n| 404 | 지유미 | 4 | 컴퓨터 |\n| 505 | 문희준 | 2 | 건축 |\n\n**<쿼리 결과>**\n| SNUM | SNAME |\n|---|---|\n| 101 | 김보라 |\n| 404 | 지유미 |\n\n① SELECT SNUM, SNAME FROM STUDENT WHERE DEPT = "컴퓨터" OR YEAR = 4\n② SELECT SNUM, SNAME AS 4 FROM STUDENT GROUP BY SNO\n③ SELECT SNUM, SNAME AS SNO FROM STUDENT GROUP BY SNAME\n④ SELECT SNUM, SNAME FROM STUDENT WHERE DEPT = "컴퓨터" AND YEAR = 4', 'MCQ', 4, '정답: 4. 결과는 DEPT가 컴퓨터이면서 YEAR가 4인 행만 포함하므로 AND 조건을 사용해야 한다.\n\n**오답 풀이**\n- 1번: OR 조건은 컴퓨터 전공이거나 4학년인 행을 모두 포함하므로 결과 행 수가 더 많아진다.\n- 2번: GROUP BY SNO가 테이블 필드와 맞지 않고 조건도 없다.\n- 3번: 조건 없이 그룹화하므로 원하는 결과가 아니다.\n- 4번: 컴퓨터 전공이면서 4학년인 학생만 조회한다.\n\n**보충 개념**\nWHERE 절에서 AND는 모든 조건을 만족하는 행만 선택한다.',
   'SQL SELECT', 2, @mock_exam_id, 52, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '보고서 작성 시 사용하는 속성에 대한 설명으로 가장 옳지 않은 것은?\n\n① 반복 실행 구역: 해당 구역이 페이지 머리글처럼 매 페이지에도 나타나도록 설정하는 속성으로, 그룹 머리글에서만 사용할 수 있다.\n② 레코드 원본: 다양한 데이터로 조회하는 SQL 문을 속성값으로 지정하여 그 결과를 보고서에 표시할 수 있다.\n③ 편집 가능: 보고서나 컨트롤의 속성으로, 보고서의 데이터를 수정할 수 있도록 하기 위해서는 이 속성 값을 ‘예’로 지정한다.\n④ 중복 내용 숨기기: 텍스트 상자와 같은 컨트롤의 속성으로, 이전 레코드와 동일한 값을 갖는 경우에는 컨트롤을 표시하지 않도록 설정한다.', 'MCQ', 3, '정답: 3. 편집 가능 속성은 주로 폼에서 레코드 편집 여부를 설정하는 속성이며, 보고서 데이터 수정용 속성으로 보기 어렵다.\n\n**오답 풀이**\n- 1번: 반복 실행 구역은 그룹 머리글의 반복 표시와 관련된다.\n- 2번: 레코드 원본에는 테이블, 쿼리, SQL 문을 지정할 수 있다.\n- 3번: 보고서는 출력용 개체이므로 데이터 편집 설명이 적절하지 않다.\n- 4번: 중복 내용 숨기기는 이전 레코드와 같은 값을 숨길 수 있다.\n\n**보충 개념**\nAccess 보고서는 데이터를 조회하고 인쇄하기 위한 개체이며, 폼은 데이터 입력과 편집에 주로 사용된다.',
   'Access 보고서 속성', 2, @mock_exam_id, 53, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '하위 폼은 주로 ‘일 대 다’ 관계가 설정된 테이블을 효과적으로 표시하기 위해 사용된다. 이때 하위 폼의 원본으로 가장 적절한 것은?\n\n① ‘일’쪽 테이블\n② ‘다’쪽 테이블\n③ ‘일’쪽 테이블과 ‘다’쪽 테이블을 모두 보여주는 쿼리\n④ ‘일’쪽 테이블로부터 만든 쿼리', 'MCQ', 2, '정답: 2. 일 대 다 관계에서 기본 폼은 ‘일’쪽, 하위 폼은 ‘다’쪽 테이블을 원본으로 사용하는 것이 일반적이다.\n\n**오답 풀이**\n- 1번: ‘일’쪽 테이블은 기본 폼의 원본으로 적합하다.\n- 2번: 하위 폼은 현재 기본 폼 레코드와 연결된 여러 ‘다’쪽 레코드를 표시한다.\n- 3번: 일반적으로 하위 폼은 다쪽 데이터를 표시한다.\n- 4번: ‘일’쪽 테이블 쿼리는 기본 폼에 더 적합하다.\n\n**보충 개념**\n하위 폼은 주문-주문상세처럼 한 레코드에 연결된 여러 세부 레코드를 표시할 때 유용하다.',
   '하위 폼', 1, @mock_exam_id, 54, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '다른 테이블을 참조하는 외래키(FK)에 대한 설명으로 가장 알맞은 것은?\n\n① 외래키 필드의 값은 유일해야 하므로 중복된 값이 입력될 수 없다.\n② 외래키 필드의 값은 널(Null) 값일 수 없으므로, 값이 반드시 입력되어야 한다.\n③ 외래키는 한 테이블에서 특정 레코드를 유일하게 구별할 수 있는 속성이다.\n④ 하나의 테이블에는 여러 개의 외래키가 존재할 수 있다.', 'MCQ', 4, '정답: 4. 하나의 테이블은 여러 다른 테이블을 참조할 수 있으므로 여러 개의 외래키를 가질 수 있다.\n\n**오답 풀이**\n- 1번: 외래키 값은 중복이 허용된다.\n- 2번: 외래키는 설정에 따라 NULL을 허용할 수 있다.\n- 3번: 레코드를 유일하게 구별하는 것은 기본키에 대한 설명이다.\n- 4번: 한 테이블에 여러 외래키가 존재할 수 있다.\n\n**보충 개념**\n외래키는 다른 테이블의 기본키를 참조하여 테이블 사이의 관계를 유지한다.',
   '외래키', 1, @mock_exam_id, 55, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '다음 설명에 해당하는 폼의 속성으로 알맞은 것은?\n\n**<보기>**\n폼 보기 상태에서의 제목 표시줄에 나타나는 텍스트를 설정한다.\n\n① 기본 보기\n② 캡션\n③ 레코드 원본\n④ 추가 가능', 'MCQ', 2, '정답: 2. 캡션 속성은 폼 창의 제목 표시줄에 표시될 텍스트를 설정한다.\n\n**오답 풀이**\n- 1번: 기본 보기는 폼의 표시 형식을 설정한다.\n- 2번: 캡션은 제목 표시줄 텍스트를 설정한다.\n- 3번: 레코드 원본은 폼에 연결할 데이터 원본을 지정한다.\n- 4번: 추가 가능은 새 레코드 추가 가능 여부를 설정한다.\n\n**보충 개념**\nAccess 개체의 캡션은 사용자에게 표시되는 제목이나 이름을 설정할 때 사용한다.',
   '폼 속성', 1, @mock_exam_id, 56, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '이벤트 프로시저에서 쿼리를 실행 모드로 여는 명령은?\n\n① DoCmd.OpenQuery\n② DoCmd.SetQuery\n③ DoCmd.OpenReport\n④ DoCmd.OpenTable', 'MCQ', 1, '정답: 1. DoCmd.OpenQuery는 Access에서 쿼리를 여는 명령이다.\n\n**오답 풀이**\n- 1번: OpenQuery는 쿼리를 실행하거나 연다.\n- 2번: SetQuery는 표준 DoCmd 메서드가 아니다.\n- 3번: OpenReport는 보고서를 연다.\n- 4번: OpenTable은 테이블을 연다.\n\n**보충 개념**\nDoCmd 개체는 Access의 매크로 동작을 VBA 코드에서 실행할 수 있게 해 준다.',
   'Access VBA', 1, @mock_exam_id, 57, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '테이블 연결을 통해 연결된 테이블과 가져오기 기능을 통해 생성된 테이블의 차이점에 대한 설명으로 옳지 않은 것은?\n\n① 연결된 테이블의 데이터를 삭제하면 연결되어 있는 원본 데이터베이스의 데이터도 삭제된다.\n② 연결된 테이블을 삭제해도 원본 테이블은 삭제되지 않는다.\n③ 가져오기 기능을 통해 생성된 테이블을 삭제해도 원본 테이블은 삭제되지 않는다.\n④ 연결된 테이블을 이용하여 폼이나 보고서를 생성할 수 있다.', 'MCQ', 1, '정답: 1. 원문 정답표 기준으로 ①이 정답으로 제시되어 있으며, 연결된 테이블은 원본 데이터를 참조하지만 연결 자체의 삭제와 원본 삭제는 구분해야 한다.\n\n**오답 풀이**\n- 1번: 정답표 기준 옳지 않은 설명에 해당한다.\n- 2번: 연결된 테이블 개체를 삭제해도 원본 테이블 자체는 삭제되지 않는다.\n- 3번: 가져온 테이블을 삭제해도 원본 데이터베이스의 테이블은 삭제되지 않는다.\n- 4번: 연결된 테이블로 폼이나 보고서를 만들 수 있다.\n\n**보충 개념**\n가져오기는 데이터를 현재 DB로 복사하고, 연결은 외부 원본과의 참조 링크를 유지한다.',
   'Access 연결 테이블', 2, @mock_exam_id, 58, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '폼을 열자마자 ‘txt조회’ 컨트롤에 커서(포커스)가 자동으로 위치하도록 하는 이벤트 프로시저는?\n\n① Private Sub txt조회_Click(): txt조회.SetFocus: End Sub\n② Private Sub txt조회_Click(): txt조회.SetFocus: End Sub\n③ Private Sub Form_Load(): txt조회.GotoControl: End Sub\n④ Private Sub Form_Load(): txt조회.SetFocus: End Sub', 'MCQ', 4, '정답: 4. 폼이 열릴 때 실행되는 Form_Load 이벤트에서 txt조회.SetFocus를 호출하면 폼이 열리는 시점에 포커스가 이동한다.\n\n**오답 풀이**\n- 1번: txt조회_Click은 컨트롤을 클릭할 때 실행되므로 폼을 열자마자 실행되지 않는다.\n- 2번: ①과 동일하게 클릭 이벤트이다.\n- 3번: GotoControl을 컨트롤 메서드처럼 사용한 형식이 부적절하다.\n- 4번: Form_Load에서 SetFocus를 호출하므로 폼이 로드될 때 포커스가 이동한다.\n\n**보충 개념**\nSetFocus 메서드는 지정한 컨트롤로 포커스를 이동시킨다.',
   'Access 이벤트 프로시저', 2, @mock_exam_id, 59, 'NONE', NULL, NOW(6), NOW(6)),
  (@sub_db, '사원정보(사번, 이름, 주소, 성별, 평가점수) 테이블에서 평가점수 필드에 1000 이상 3000 이하의 값만 입력되도록 범위를 지정하려고 할 때 사용하는 필드 속성은?\n\n① IME 모드\n② 입력 마스크\n③ 유효성 검사 규칙\n④ 인덱스', 'MCQ', 3, '정답: 3. 유효성 검사 규칙은 필드에 입력 가능한 값의 조건이나 범위를 제한하는 속성이다.\n\n**오답 풀이**\n- 1번: IME 모드는 한글·영문 입력 상태와 관련된다.\n- 2번: 입력 마스크는 입력 형식을 제한한다.\n- 3번: 유효성 검사 규칙은 필드에 입력 가능한 값의 조건이나 범위를 제한하는 속성이다.\n- 4번: 인덱스는 검색과 정렬 성능을 높이는 속성이다.\n\n**보충 개념**\n평가점수 범위 제한은 `Between 1000 And 3000` 같은 유효성 검사 규칙으로 설정할 수 있다.',
   '유효성 검사 규칙', 1, @mock_exam_id, 60, 'NONE', NULL, NOW(6), NOW(6))
;
